import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "How deep should mulch be?", a: "Most plants benefit from 2-4 inches of mulch. Less than 2 inches may not suppress weeds effectively. More than 4 inches can suffocate roots and prevent water from reaching the soil. Keep mulch 2-3 inches away from tree trunks and plant stems to prevent rot and rodent damage." },
  { q: "How many cubic yards of mulch do I need?", a: "Multiply area (sq ft)  x  depth (inches)  x  324. The divisor 324 comes from converting: 12 inches/foot  x  27 cubic feet/cubic yard. Example: 500 sq ft at 3 inches deep = 500  x  3  x  324 = 4.63 cubic yards of mulch." },
  { q: "How many bags of mulch equal a cubic yard?", a: "A 2-cubic-foot bag: 13.5 bags per cubic yard. A 3-cubic-foot bag: 9 bags per cubic yard. For areas over 5 cubic yards, bulk mulch delivered by the yard is significantly less expensive - often 50% less per cubic foot than bagged mulch." },
  { q: "What type of mulch is best?", a: "Wood chip mulch (shredded hardwood, cedar) is excellent for landscape beds - suppresses weeds, retains moisture, and improves soil. Straw is ideal for vegetable gardens. Pine needles suit acid-loving plants like azaleas and blueberries. Rubber mulch works well for playgrounds. Avoid dyed mulches near edible plants." },
  { q: "Does mulch prevent weeds?", a: "Yes - 2-4 inches of mulch blocks light, preventing most weed seeds from germinating. For best results, apply mulch after hand-weeding or using a pre-emergent herbicide. Adding landscape fabric under mulch further reduces weeds but can interfere with soil health over time - wood chip mulch without fabric is often preferred." },
  { q: "When is the best time to apply mulch?", a: "Spring: after soil warms but before weed germination - late April to early May in most US climates. Fall: after the first frost to insulate roots over winter. Avoid mulching in late summer, which can trap moisture and promote fungal disease. Topdress 1-2 inches annually as existing mulch decomposes." },
  { q: "How much does mulch cost?", a: "Bagged mulch (2 cu ft): $3-$6 per bag ($40-$80/cubic yard). Bulk delivered: $25-$45 per cubic yard depending on type and location. Pine bark and cedar cost more; dyed wood chip mulch costs less. Free wood chip mulch is often available from tree-trimming companies and local municipalities." },
  { q: "How does mulch depth affect plant roots?", a: "2-3 inches suppresses weeds and retains moisture without restricting roots. 4 inches is ideal for new plantings and established shrubs. More than 4 inches can reduce oxygen to roots, intercept rainfall before it reaches the soil, and create 'mulch volcanoes' against trunks that cause bark decay and root circling." },
];

const MULCH_TYPES = [
  ["Shredded hardwood", "2-3 in", "Landscape beds, trees", "Breaks down slowly, improves soil"],
  ["Wood chips", "3-4 in", "Paths, around trees", "Very long-lasting, attracts beneficial fungi"],
  ["Cedar bark", "2-3 in", "Landscape beds", "Natural insect repellent, slow decay"],
  ["Pine bark nuggets", "2-3 in", "Shrubs, acid-lovers", "Floats in heavy rain; good drainage"],
  ["Pine needles (straw)", "2-4 in", "Acid-loving plants", "Acidifies soil slightly over time"],
  ["Straw", "3-4 in", "Vegetable gardens", "Decomposes quickly, adds nutrients"],
  ["Rubber mulch", "2-3 in", "Playgrounds, paths", "Permanent, no decomposition"],
  ["Cocoa hull", "1-2 in", "Ornamentals", "Rich color, pleasant smell; toxic to dogs"],
];

export default function MulchCalculator() {
  const [length, setLength] = useState(20);
  const [width, setWidth] = useState(10);
  const [depth, setDepth] = useState(3);
  const [bagSize, setBagSize] = useState(2);

  const area = length * width;
  const cubicFeet = area * (depth / 12);
  const cubicYards = cubicFeet / 27;
  const bags = Math.ceil(cubicFeet / bagSize);
  const estimatedCost = cubicYards * 35;

  const depthRows = [1, 2, 3, 4, 5, 6];

  return (
    <>
      <SEOHead
        title="Free Mulch Calculator Online - Calculate Cubic Yards and Bags of Mulch Instantly | CalcHive"
        description="Free online mulch calculator. Calculate cubic yards and bags of mulch needed for any garden bed at any depth instantly. 100% free for gardeners and landscapers, no signup required."
        canonical="/mulch-calculator"
        keywords="free mulch calculator, mulch calculator online free, cubic yards mulch calculator free, how much mulch do I need calculator free, garden mulch estimator free"
        category="Construction Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-stone-600 dark:text-stone-400 bg-stone-100 dark:bg-stone-800/50 px-3 py-1 rounded-full mb-4 inline-block">Housing</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Mulch Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free mulch calculator to estimate cubic yards and bags for any garden bed depth. This mulch calculator online free also works as a cubic yards mulch calculator free, how much mulch do I need calculator free, and garden mulch estimator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="length" label="Area Length (ft)" value={length} min={1} max={200} step={1} onChange={setLength} format={v => `${v} ft`} testId="input-length" />
            <SliderInput id="width" label="Area Width (ft)" value={width} min={1} max={200} step={1} onChange={setWidth} format={v => `${v} ft`} testId="input-width" />
            <SliderInput id="depth" label="Desired Depth (inches)" value={depth} min={1} max={6} step={0.5} onChange={setDepth} format={v => `${v}"`} testId="input-depth" helpText="Recommended: 2-4 in for most plants" />
            <SliderInput id="bag" label="Bag Size (cu ft)" value={bagSize} min={1} max={3} step={0.5} onChange={setBagSize} format={v => `${v} cu ft`} testId="input-bag" helpText="Common sizes: 2 cu ft and 3 cu ft bags" />
          </div>
          <motion.div key={`${length}-${width}-${depth}-${bagSize}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-stone-600 to-stone-800 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Cubic Yards Needed</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-yards">{cubicYards.toFixed(2)}</p>
              <p className="text-white/70 text-sm mt-1">cubic yards - {cubicFeet.toFixed(1)} cu ft</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Coverage Area", value: `${area.toLocaleString()} sq ft` },
                { label: `Bags (${bagSize} cu ft)`, value: `${bags} bags` },
                { label: "Est. Bulk Cost", value: `~$${estimatedCost.toFixed(0)}` },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-base font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
            <p className="text-xs text-muted-foreground mt-3 text-center">Add 5-10% extra for uneven ground and waste. Bulk cost estimate at ~$35/cu yd.</p>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate How Much Mulch You Need for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Mulch is sold by volume - cubic yards for bulk delivery, cubic feet for bagged mulch. The calculation is simple: find the area in square feet, multiply by your desired depth converted to feet, and divide by 27 to get cubic yards.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Cubic Feet = Length (ft)  x  Width (ft)  x  Depth (ft)</p>
            <p>Cubic Yards = Cubic Feet  x  27</p>
            <p>Bags needed = Cubic Feet  x  Bag Size (cu ft)</p>
            <p className="text-xs text-muted-foreground mt-2">Note: Depth in inches - Depth in feet = Depth  x  12</p>
            <p className="text-xs text-muted-foreground">Quick formula: Cubic Yards = Area (sq ft)  x  Depth (in)  x  324</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Cubic Yards and Bags of Mulch for Any Garden Bed</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Depth", "Cubic Yards", "Cubic Feet", `Bags (${bagSize} cu ft)`, "Use Case"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {depthRows.map(d => {
                  const cf = area * (d / 12);
                  const cy = cf / 27;
                  const b = Math.ceil(cf / bagSize);
                  const use = d <= 1 ? "Light top-dress" : d <= 2 ? "Minimum weed control" : d <= 3 ? "Standard garden bed" : d <= 4 ? "New planting, trees" : "Winter insulation";
                  return (
                    <tr key={d} className={`hover:bg-muted/30 ${d === depth ? "bg-stone-50 dark:bg-stone-800/30 font-semibold" : ""}`}>
                      <td className="py-2.5 px-4 font-semibold text-foreground">{d}"{d === depth ? " (current)" : ""}</td>
                      <td className="py-2.5 px-4 text-stone-600 dark:text-stone-400 font-bold">{cy.toFixed(2)} cu yd</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{cf.toFixed(1)} cu ft</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{b} bags</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{use}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Garden Mulch Estimator for Gardeners and Landscapers</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Mulch Type", "Ideal Depth", "Best For", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {MULCH_TYPES.map(([type, depth_, bestFor, notes]) => (
                  <tr key={type} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{type}</td>
                    <td className="py-2.5 px-4 text-stone-600 dark:text-stone-400 font-medium">{depth_}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{bestFor}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/mulch-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


